class Solution:
    def smallestAbsent(self, nums):
        n = len(nums)
        present = set(nums)
        start = sum(nums) // n + 1
        if start < 1:
            start = 1
        c = start
        while c in present or c * n <= sum(nums):
            c += 1
        return c

solutions.javascript:
var smallestAbsent = function(nums) {
    const n = nums.length;
    const total = nums.reduce((a, b) => a + b, 0);
    const present = new Set(nums);
    let c = Math.floor(total / n) + 1;
    if (c < 1) c = 1;
    while (present.has(c) || c * n <= total) c++;
    return c;
};
